    let (content, _thinking, _done_reason) = proxy_chat(GEMMA4_26B, None, "What is 2+2? Just the number.");
    assert!(!content.is_empty(), "gemma-4-26b should return content via proxy");
    eprintln!("gemma-4-26b proxy response: {:?}", content);
}

