fn proxy_chat(model: &str, system: Option<&str>, user: &str) -> (String, String, String) {
    let messages = if let Some(sys) = system {
        format!(
            r#"[{{"role":"system","content":{}}},{{"role":"user","content":{}}}]"#,
            serde_json_str(sys), serde_json_str(user)
        )
