        format!(r#"[{{"role":"user","content":{}}}]"#, serde_json_str(user))
    };
    let body = format!(
        r#"{{"model":{},"stream":false,"messages":{}}}"#,
        serde_json_str(model), messages
    );
    let out = std::process::Command::new("curl")
        .args(["-sf", "--max-time", "60", &format!("{}/api/chat", PROXY_ENDPOINT), "-d", &body])
        .output()
