erly. Looking at the file tree, I see `tests/tools_integration.rs` and `tests/model_compat.rs`. I should investigate these files to see what kind of testing is already in place and then propose or implement a command (perhaps a slash command or a specialized test runner) that specifically validates the model's ability to generate valid tool-calling JSON or specific formats (Qwen/Gemma/Bracket) as specified in `AGENTS.md`.]<tool>shell</tool><command>ls tests/</command><desc>Listing the existing test files to identify existing tool-calling validation logic.</desc>\\\",\\\"ts\\\":1776963543}\\n+{\\\"role\\\":\\\"tool\\\",\\\"content\\\":\\\"[TOOL_OUTPUT: shell = agent_agentic_loop.rs\\\\nintegration_tests.rs\\\\nmodel_compat.rs\\\\nollama_integration_tests.rs\\\\nspawn_shell_patterns.rs\\\\ntest_session_creation.rs\\\\ntools_integration.rs]\\\",\\\"ts\\\":1776963543}\\n+{\\\"role\\\":\\\"assistant\\\",\\\"content\\\":\\\"[THINK: The user wants a robust way to ensure models can tool call properly. I see `tests/tools_integration.rs` and `tests/model_compat.rs`. I'll start by examining `tests/tools_integration.rs` to see how tool calling is currently tested, then `tests/model_compat.rs` to see how model-specific formats are handled. My goal is to propose or implement a dedicated command (likely a slash command like `/test_tools`) that runs a suite of model-specific tool-calling validation tests.]<tool>shell</tool><command>cat tests/tools_integration.rs</command><desc>Reading the existing tool integration tests to understand the current validation coverage.</desc>\\\",\\\"ts\\\":1776963546}\\n+{\\\"role\\\":\\\"tool\\\",\\\"content\\\":\\\"[TOOL_OUTPUT: shell = /// Integration tests for tools system\\\\n/// Tests the complete tool execution pipeline\\\\n\\\\n#[cfg(test)]\\\\nmod tests {\\\\n    use yggdra::tools::{Tool, ToolRegistry, RipgrepTool, CommitTool, EditfileTool, PythonTool, ExecTool, RusteTool};\\\\n    use yggdra::config::CapabilityProfile;\\\\n    use std::fs;\\\\n    use tempfile::TempDir;\\\\n    #[allow(unused_imports)]\\\\n    use std::env;\\\\n\\\\n    #[test]\\\\n    fn test_tool_registry_all_tools_present() {\\\\n        let registry = ToolRegistry::new(CapabilityProfile::Standard);\\\\n        let tools = registry.list_tools();\\\\n\\\\n        // The `spawn` tool was renamed to `exec`; `editfile` was split into\\\\n        // `setfile`/`patchfile`. Assert the current canonical tool set.\\\\n        assert!(tools.contains(&\\\\\\\"rg\\\\\\\"), \\\\\\\"rg tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"exec\\\\\\\"), \\\\\\\"exec tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"setfile\\\\\\\"), \\\\\\\"setfile tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"patchfile\\\\\\\"), \\\\\\\"patchfile tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"commit\\\\\\\"), \\\\\\\"commit tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"python\\\\\\\"), \\\\\\\"python tool not in registry\\\\\\\");\\\\n        assert!(tools.contains(&\\\\\\\"ruste\\\\\\\"), \\\\\\\"ruste tool not in registry\\\\\\\");\\\\n    }\\\\n\\\\n    // Removed test_ripgrep_blocks_dangerous_patterns: rg's validate_input no longer scans\\\\n    // the *pattern* for shell metacharacters. The tool is now invoked via Command (no shell),\\\\n    // so '|', ';', '&&', backticks, etc. are literal characters in the search pattern and\\\\n    // pose no command-injection risk. Path-based sandboxing remains via sandbox::check_read.\\\\n\\\\n    #[test]\\\\n    fn test_editfile_blocks_path_traversal() {\\\\n        // Initialize sandbox to the cargo manifest dir (repo root) so check_write\\\\n        // actually fires. Without init the sandbox is permissive.\\\\n        yggdra::sandbox::init(std::path::PathBuf::from(env!(\\\\\\\"CARGO_MANIFEST_DIR\\\\\\\")));\\\\n\\\\n        let tool = EditfileTool;\\\\n\\\\n        // Helper: build full args with null-sep format\\\\n        let args = |path: &str| format!(\\\\\\\"{}\\\\\\\\x00old text\\\\\\\\x00new text\\\\\\\", path);\\\\n\\\\n        // Should block path traversal\\\\n        assert!(tool.validate_input(&args(\\\\\\\"../../../etc/passwd\\\\\\\")).is_err());\\\\n        assert!(tool.validate_input(&args(\\\\\\\"../../sensitive/file.txt\\\\\\\")).is_err());\\\\n\\\\n        // Should block system files\\\\n        assert!(tool.validate_input(&args(\\\\\\\"/etc/passwd\\\\\\\")).is_err());\\\\n        assert!(tool.validate_input(&args(\\\\\\\"/bin/bash\\\\\\\")).is_err());\\\\n\\\\n        // Relative paths should be OK\\\\n        assert!(tool.validate_input(&args(\\\\\\\"myfile.txt\\\\\\\")).is_ok());\\\\n        assert!(tool.validate_input(&args(\\\\\\\"./directory/file.txt\\\\\\\")).is_ok());\\\\n\\\\n        // Missing separator format should fail\\\\n        assert!(tool.validate_input(\\\\\\\"myfile.txt\\\\\\\").is_err());\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_commit_tool_validation() {\\\\n        let tool = CommitTool;\\\\n        \\\\n        // Empty message should fail\\\\n        assert!(tool.validate_input(\\\\\\\"\\\\\\\").is_err());\\\\n        \\\\n        // Non-empty message should pass validation\\\\n        assert!(tool.validate_input(\\\\\\\"fix: bug in parser\\\\\\\").is_ok());\\\\n        assert!(tool.validate_input(\\\\\\\"docs: update readme\\\\\\\").is_ok());\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_python_tool_blocks_network_imports() {\\\\n        let temp_dir = TempDir::new().expect(\\\\\\\"Failed to create temp dir\\\\\\\");\\\\n        let script_path = temp_dir.path().join(\\\\\\\"test.py\\\\\\\");\\\\n\\\\n        // Create a script with dangerous imports\\\\n        let dangerous_script = r#\\\\\\\"\\\\nimport requests\\\\nprint(\\\\\\\"This should be blocked\\\\\\\")\\\\n\\\\\\\"#;\\\\n        fs::write(&script_path, dangerous_script).expect(\\\\\\\"Failed to write test script\\\\\\\");\\\\n\\\\n        let tool = PythonTool;\\\\n        let path_str = script_path.to_string_lossy().to_string();\\\\n        \\\\n        // Should reject scripts with network imports\\\\n        assert!(tool.validate_input(&path_str).is_err(), \\\\\\\"Should block requests import\\\\\\\");\\\\n\\\\n        // Create a safe script\\\\n        let safe_script = r#\\\\\\\"\\\\nprint(\\\\\\\"Hello, World!\\\\\\\")\\\\n\\\\\\\"#;\\\\n        fs::write(&script_path, safe_script).expect(\\\\\\\"Failed to write safe script\\\\\\\");\\\\n        \\\\n        // Should accept safe scripts\\\\n        assert!(tool.validate_input(&path_str).is_ok(), \\\\\\\"Should allow safe scripts\\\\\\\");\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_tool_registry_dispatch() {\\\\n        let registry = ToolRegistry::new(CapabilityProfile::Standard);\\\\n        \\\\n        // Dispatch to unknown tool should fail\\\\n        let result = registry.execute(\\\\\\\"nonexistent\\\\\\\", \\\\\\\"args\\\\\\\");\\\\n        assert!(result.is_err());\\\\n        assert!(result.unwrap_err().to_string().contains(\\\\\\\"unknown tool\\\\\\\"));\\\\n        \\\\n        // Dispatch with empty args to known tool should fail validation\\\\n        let result = registry.execute(\\\\\\\"rg\\\\\\\", \\\\\\\"\\\\\\\");\\\\n        assert!(result.is_err(), \\\\\\\"rg should reject empty args\\\\\\\");\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_tool_network_escapes_blocked() {\\\\n        let registry = ToolRegistry::new(CapabilityProfile::Standard);\\\\n        \\\\n        // Try to execute curl via rg - should be blocked\\\\n        let result = registry.execute(\\\\\\\"rg\\\\\\\", \\\\\\\"curl http://evil.com .\\\\\\\");\\\\n        assert!(result.is_err(), \\\\\\\"Should block curl attempt\\\\\\\");\\\\n        \\\\n        // Try to execute wget via python - should be blocked by import scan\\\\n        let result = registry.execute(\\\\\\\"python\\\\\\\", \\\\\\\"/tmp/nonexistent_wget_script.py\\\\\\\");\\\\n        assert!(result.is_err(), \\\\\\\"Should reject nonexistent file\\\\\\\");\\\\n    }\\\\n\\\\n    // Removed test_tool_safety_chain: same rationale as test_ripgrep_blocks_dangerous_patterns —\\\\n    // shell-metacharacter scanning was dropped from rg's validate_input because rg is now spawned\\\\n    // without a shell, making such patterns harmless literals.\\\\n\\\\n    #[test]\\\\n    fn test_spawn_clock_exercise() {\\\\n        let tool = ExecTool;\\\\n        \\\\n        // Test date command\\\\n        let result = tool.execute(\\\\\\\"date\\\\\\\");\\\\n        assert!(result.is_ok(), \\\\\\\"spawn date should succeed\\\\\\\");\\\\n        let output = result.unwrap();\\\\n        assert!(!output.is_empty(), \\\\\\\"date output should not be empty\\\\\\\");\\\\n        // Output typically contains timestamp info\\\\n        assert!(output.len() > 10, \\\\\\\"date output should be reasonable length\\\\\\\");\\\\n        \\\\n        // Test uname command\\\\n        let result = tool.execute(\\\\\\\"uname -s\\\\\\\");\\\\n        assert!(result.is_ok(), \\\\\\\"spawn uname -s should succeed\\\\\\\");\\\\n        let output = result.unwrap();\\\\n        assert!(!output.is_empty(), \\\\\\\"uname output should not be empty\\\\\\\");\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_spawn_arbitrary_commands() {\\\\n        let tool = ExecTool;\\\\n        \\\\n        // Test ls command (should list current directory)\\\\n        let result = tool.execute(\\\\\\\"ls\\\\\\\");\\\\n        assert!(result.is_ok(), \\\\\\\"spawn ls should succeed\\\\\\\");\\\\n        let output = result.unwrap();\\\\n        assert!(!output.is_empty(), \\\\\\\"ls output should not be empty\\\\\\\");\\\\n        \\\\n        // Test wc with echo piping (via separate commands)\\\\n        let result = tool.execute(\\\\\\\"pwd\\\\\\\");\\\\n        assert!(result.is_ok(), \\\\\\\"spawn pwd should succeed\\\\\\\");\\\\n        let pwd_output = result.unwrap();\\\\n        assert!(pwd_output.contains(\\\\\\\"/\\\\\\\"), \\\\\\\"pwd output should contain path separator\\\\\\\");\\\\n        \\\\n        // Test uname -a (multi-word command)\\\\n        let result = tool.execute(\\\\\\\"uname -a\\\\\\\");\\\\n        assert!(result.is_ok(), \\\\\\\"spawn uname -a should succeed\\\\\\\");\\\\n        let output = result.unwrap();\\\\n        assert!(!output.is_empty(), \\\\\\\"uname -a output should not be empty\\\\\\\");\\\\n    }\\\\n\\\\n    #[test]\\\\n    fn test_ruste_clock_exercise() {\\\\n        let tool = RusteTool;\\\\n        let temp_dir = TempDir::new().expect(\\\\\\\"Failed to create temp dir\\\\\\\");\\\\n        let script_path = temp_dir.path().join(\\\\\\\"clock_exercise.rs\\\\\\\");\\\\n\\\\n        // Write a simple Rust program that outputs the current time\\\\n        let rust_code = r#\\\\\\\"\\\\nfn main() {\\\\n    use std::time::{SystemTime, UNIX_EPOCH};\\\\n    let secs = SystemTime::now()\\\\n        .duration_since(UNIX_EPOCH)\\\\n        .unwrap()\\\\n        .as_secs();\\\\n    let h = (secs % 86400) / 3600;\\\\n    let m = (secs % 3600) / 60;\\\\n    let s = secs % 60;\\\\n    println!(\\\\\\\"UTC {:02}:{:02}:{:02}\\\\\\\", h, m, s);\\\\n    println!(\\\\\\\"Program executed successfully!\\\\\\\");\\\\n}\\\\n\\\\\\\"#;\\\\n        fs::write(&script_path, rust_code).expect(\\\\\\\"Failed to write rust script\\\\\\\");\\\\n\\\\n        let path_str = script_path.to_string_lossy().to_string();\\\\n        \\\\n        // Execute the ruste tool\\\\n        let result = tool.execute(&path_str);\\\\n        assert!(result.is_ok(), \\\\\\\"ruste should compile and execute the program: {:?}\\\\\\\", result);\\\\n        \\\\n        let output = result.unwrap();\\\\n        assert!(!output.is_empty(), \\\\\\\"Program output should not be empty\\\\\\\");\\\\n        assert!(output.contains(\\\\\\\"UTC\\\\\\\"), \\\\\\\"Output should contain 'UTC' timestamp\\\\\\\");\\\\n        assert!(output.contains(\\\\\\\"successfully\\\\\\\"), \\\\\\\"Output should confirm success\\\\\\\");\\\\n    }\\\\n}]\\\",\\\"ts\\\":1776963546}\\n+{\\\"role\\\":\\\"assistant\\\",\\\"content\\\":\\\"[THINK: `tests/tools_integration.rs` focuses on the *implementation* of the tools (validation, registry, and basic execution of commands like `date` or `ls`). It does **not** test the model's ability to actually *generate* the tool calls.\\\\n\\\\nTo solve the user's request, we need a test that:\\\\n1. Uses an LLM (via `OllamaClient`).\\\\n2. Provides a prompt that requires a tool call.\\\\n3. Parses the model's response using `agent::parse_tool_calls`.\\\\n4. Verifies that the parsed output matches the expected tool and arguments.\\\\n\\\\nI'll check `tests/model_compat.rs` to see if there is any existing logic for testing model-to-tool-call conversion.]<tool>shell</tool><command>cat tests/model_compat.rs</command><desc>Reading model_compat.rs to see if there's existing logic for validating model tool-calling formats.</desc>\\\",\\\"ts\\\":1776963550}\\n+{\\\"role\\\":\\\"tool\\\",\\\"content\\\":\\\"[TOOL_OUTPUT: shell = /// Model compatibility tests — run manually, never in CI.\\\\n///\\\\n/// These tests verify that each supported model:\\\\n///   1. Returns non-empty content for plain questions\\\\n///   2. Emits tool calls in the expected format\\\\n///   3. Correctly handles thinking vs content fields\\\\n///   4. Multiline writefile content is parsed correctly\\\\n///\\\\n/// Run all:       cargo test --test model_compat -- --ignored\\\\n/// Run one model: cargo test --test model_compat gemma_heretic -- --ignored\\\\n\\\\nuse yggdra::agent::parse_tool_calls;\\\\nuse yggdra::config::CapabilityProfile;\\\\n\\\\nconst OLLAMA_ENDPOINT: &str = \\\\\\\"http://localhost:11434\\\\\\\";\\\\n\\\\n/// Returns true if Ollama is reachable.\\\\nfn ollama_available() -> bool {\\\\n    std::process::Command::new(\\\\\\\"curl\\\\\\\")\\\\n        .args([\\\\\\\"-sf\\\\\\\", &format!(\\\\\\\"{}/api/tags\\\\\\\", OLLAMA_ENDPOINT)])\\\\n        .output()\\\\n        .map(|o| o.status.success())\\\\n        .unwrap_or(false)\\\\n}\\\\n\\\\n/// Returns true if the named model is pulled.\\\\nfn model_available(model: &str) -> bool {\\\\n    let out = std::process::Command::new(\\\\\\\"curl\\\\\\\")\\\\n        .args([\\\\\\\"-sf\\\\\\\", &format!(\\\\\\\"{}/api/tags\\\\\\\", OLLAMA_ENDPOINT)])\\\\n        .output();\\\\n    match out {\\\\n        Ok(o) => String::from_utf8_lossy(&o.stdout).contains(model),\\\\n        Err(_) => false,\\\\n    }\\\\n}\\\\n\\\\n/// Send a single-turn chat request and return (content, thinking, done_reason).\\\\nfn chat(model: &str, system: Option<&str>, user: &str) -> (String, String, String) {\\\\n    let messages = if let Some(sys) = system {\\\\n        format!(\\\\n            r#\\\\\\\"[{{\\\\\\\"role\\\\\\\":\\\\\\\"system\\\\\\\",\\\\\\\"content\\\\\\\":{}}},{{\\\\\\\"role\\\\\\\":\\\\\\\"user\\\\\\\",\\\\\\\"content\\\\\\\":{}}}]\\\\\\\"#,\\\\n            serde_json_str(sys),\\\\n            serde_json_str(user)\\\\n        )\\\\n    } else {\\\\n        format!(r#\\\\\\\"[{{\\\\\\\"role\\\\\\\":\\\\\\\"user\\\\\\\",\\\\\\\"content\\\\\\\":{}}}]\\\\\\\"#, serde_json_str(user))\\\\n    };\\\\n\\\\n    let body = format!(\\\\n        r#\\\\\\\"{{\\\\\\\"model\\\\\\\":{},\\\\\\\"stream\\\\\\\":false,\\\\\\\"options\\\\\\\":{{\\\\\\\"num_ctx\\\\\\\":4096,\\\\\\\"num_predict\\\\\\\":300}},\\\\\\\"messages\\\\\\\":{}}}\\\\\\\"#,\\\\n        serde_json_str(model),\\\\n        messages\\\\n    );\\\\n\\\\n    let out = std::process::Command::new(\\\\\\\"curl\\\\\\\")\\\\n        .args([\\\\\\\"-sf\\\\\\\", &format!(\\\\\\\"{}/api/chat\\\\\\\", OLLAMA_ENDPOINT), \\\\\\\"-d\\\\\\\", &body])\\\\n        .output()\\\\n        .expect(\\\\\\\"curl failed\\\\\\\");\\\\n\\\\n    let json = String::from_utf8_lossy(&out.stdout);\\\\n\\\\n    let content = extract_json_str(&json, \\\\\\\"\\\\\\\\\\\\\\\"content\\\\\\\\\\\\\\\":\\\\\\\");\\\\n    let thinking = extract_json_str(&json, \\\\\\\"\\\\\\\\\\\\\\\"thinking\\\\\\\\\\\\\\\":\\\\\\\");\\\\n    let done_reason = extract_json_str(&json, \\\\\\\"\\\\\\\\\\\\\\\"done_reason\\\\\\\\\\\\\\\":\\\\\\\");\\\\n\\\\n    (content, thinking, done_reason)\\\\n}\\\\n\\\\n/// Minimal JSON string escaper for test payloads.\\\\nfn serde_json_str(s: &str) -> String {\\\\n    let escaped = s\\\\n        .replace('\\\\\\\\\\\\\\\\', \\\\\\\"\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\")\\\\n        .replace('\\\\\\\"', \\\\\\\"\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\\"\\\\\\\")\\\\n        .replace('\\\\\\\\n', \\\\\\\"\\\\\\\\\\\\\\\\n\\\\\\\")\\\\n        .replace('\\\\\\\\r', \\\\\\\"\\\\\\\\\\\\\\\\r\\\\\\\")\\\\n        .replace('\\\\\\\\t', \\\\\\\"\\\\\\\\\\\\\\\\t\\\\\\\");\\\\n    format!(\\\\\\\"\\\\\\\\\\\\\\\"{}\\\\\\\\\\\\\\\"\\\\\\\", escaped)\\\\n}\\\\n\\\\n/// Extract first string value for a given key from raw JSON (good enough for tests).\\\\nfn extract_json_str(json: &str, key: &str) -> String {\\\\n    if let Some(pos) = json.find(key) {\\\\n        let after = &json[pos + key.len()..].trim_start();\\\\n        if after.starts_with('\\\\\\\"') {\\\\n            let inner = &after[1..];\\\\n            let mut result = String::new();\\\\n            let mut chars = inner.chars();\\\\n            while let Some(c) = chars.next() {\\\\n                match c {\\\\n                    '\\\\\\\"' => break,\\\\n                    '\\\\\\\\\\\\\\\\' => match chars.next() {\\\\n                        Some('n') => result.push('\\\\\\\\n'),\\\\n                        Some('t') => result.push('\\\\\\\\t'),\\\\n                        Some('u') => {\\\\n                            // Handle \\\\\\\\uXXXX unicode escape\\\\n                            let hex: String = chars.by_ref().take(4).collect();\\\\n                            if let Ok(code) = u32::from_str_radix(&hex, 16) {\\\\n                                if let Some(ch) = char::from_u32(code) {\\\\n                                    result.push(ch);\\\\n                                }\\\\n                            }\\\\n                        }\\\\n                        Some(c) => result.push(c),\\\\n                        None => break,\\\\n                    },\\\\n                    c => result.push(c),\\\\n                }\\\\n            }\\\\n            return result;\\\\n        }\\\\n    }\\\\n    String::new()\\\\n}\\\\n\\\\n/// System prompt using standard <|tool> format.\\\\nfn std_tool_system() -> &'static str {\\\\n    \\\\\\\"You are a helpful agent.\\\\\\\\n\\\\\\\\\\\\n     FORMAT: <|tool>name<|tool_sep>arg<|end_tool>\\\\\\\\n\\\\\\\\\\\\n     EXAMPLES:\\\\\\\\n\\\\\\\\\\\\n     <|tool>readfile<|tool_sep>src/main.rs<|end_tool>\\\\\\\"\\\\n}\\\\n\\\\n/// System prompt using bracket [TOOL: ...] format.\\\\nfn bracket_tool_system() -> &'static str {\\\\n    \\\\\\\"You are a helpful agent.\\\\\\\\n\\\\\\\\\\\\n     FORMAT: [TOOL: name arg]\\\\\\\\n\\\\\\\\\\\\n     EXAMPLES:\\\\\\\\n\\\\\\\\\\\\n     [TOOL: readfile src/main.rs]\\\\\\\"\\\\n}\\\\n\\\\n// ─── gemma-4-heretic:q4k ────────────────────────────────────────────────────\\\\n\\\\nconst GEMMA_HERETIC: &str = \\\\\\\"gemma-4-heretic:q4k\\\\\\\";\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_gemma_heretic_plain_response() {\\\\n    if !ollama_available() || !model_available(GEMMA_HERETIC) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", GEMMA_HERETIC);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(GEMMA_HERETIC, None, \\\\\\\"What is 2+2? Just the number.\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\", \\\\\\\"should stop cleanly\\\\\\\");\\\\n    assert!(!content.is_empty(), \\\\\\\"plain response should have content\\\\\\\");\\\\n    assert!(content.contains('4'), \\\\\\\"should contain the answer\\\\\\\");\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_gemma_heretic_standard_format_suppresses_content() {\\\\n    if !ollama_available() || !model_available(GEMMA_HERETIC) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", GEMMA_HERETIC);\\\\n        return;\\\\n    }\\\\n    let (content, thinking, done_reason) = chat(GEMMA_HERETIC, Some(std_tool_system()), \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    // Gemma heretic suppresses content when <|tool> tokens appear in context\\\\n    assert!(content.is_empty(), \\\\\\\"gemma heretic should produce empty content with <|tool> prompt (got: {:?})\\\\\\\", content);\\\\n    assert!(!thinking.is_empty(), \\\\\\\"thinking should be populated\\\\\\\");\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_gemma_heretic_bracket_format_works() {\\\\n    if !ollama_available() || !model_available(GEMMA_HERETIC) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", GEMMA_HERETIC);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(GEMMA_HERETIC, Some(bracket_tool_system()), \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty(), \\\\\\\"bracket format should produce content\\\\\\\");\\\\n    let calls = parse_tool_calls(&content, CapabilityProfile::Standard);\\\\n    assert!(!calls.is_empty(), \\\\\\\"should parse at least one tool call, got content: {:?}\\\\\\\", content);\\\\n    assert_eq!(calls[0].name, \\\\\\\"readfile\\\\\\\");\\\\n}\\\\n\\\\n// removed *_detect_tool_format test: detect_tool_format/ToolFormat removed from public API\\\\n#[test]\\\\n#[ignore]\\\\nfn test_gemma_heretic_writefile_multiline() {\\\\n    if !ollama_available() || !model_available(GEMMA_HERETIC) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", GEMMA_HERETIC);\\\\n        return;\\\\n    }\\\\n    let system = \\\\\\\"You are a helpful agent.\\\\\\\\n\\\\\\\\\\\\n        FORMAT: [TOOL: name arg]\\\\\\\\n\\\\\\\\\\\\n        For writefile, the first line after the tool name is the path, the rest is content.\\\\\\\\n\\\\\\\\\\\\n        EXAMPLE: [TOOL: writefile src/hello.rs\\\\\\\\nfn main() {}\\\\\\\\n]\\\\\\\";\\\\n    let (content, _thinking, _) = chat(GEMMA_HERETIC, Some(system),\\\\n        \\\\\\\"Write a Rust hello world to src/hello.rs\\\\\\\");\\\\n    let calls = parse_tool_calls(&content, CapabilityProfile::Standard);\\\\n    let wf = calls.iter().find(|c| c.name == \\\\\\\"writefile\\\\\\\");\\\\n    assert!(wf.is_some(), \\\\\\\"should have a writefile call, content: {:?}\\\\\\\", content);\\\\n    let args = &wf.unwrap().args;\\\\n    assert!(args.contains('\\\\\\\\x00'), \\\\\\\"writefile args should be path\\\\\\\\\\\\\\\\x00content separated\\\\\\\");\\\\n    let (path, file_content) = args.split_once('\\\\\\\\x00').unwrap();\\\\n    assert!(!path.is_empty(), \\\\\\\"path should be non-empty\\\\\\\");\\\\n    assert!(!file_content.is_empty(), \\\\\\\"file content should be non-empty\\\\\\\");\\\\n}\\\\n\\\\n// ─── qwen3.5:4b ─────────────────────────────────────────────────────────────\\\\n\\\\nconst QWEN35_4B: &str = \\\\\\\"qwen3.5:4b\\\\\\\";\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_qwen35_4b_plain_response() {\\\\n    if !ollama_available() || !model_available(QWEN35_4B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", QWEN35_4B);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(QWEN35_4B, None, \\\\\\\"What is 2+2? Just the number.\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty(), \\\\\\\"plain response should have content\\\\\\\");\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_qwen35_4b_json_format_emits_content() {\\\\n    if !ollama_available() || !model_available(QWEN35_4B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", QWEN35_4B);\\\\n        return;\\\\n    }\\\\n    let system_prompt = \\\\\\\"You MUST respond ONLY with JSON in this format:\\\\\\\\n\\\\\\\\\\\\n        {\\\\\\\\\\\\\\\"tool_calls\\\\\\\\\\\\\\\": [{\\\\\\\\\\\\\\\"name\\\\\\\\\\\\\\\": \\\\\\\\\\\\\\\"readfile\\\\\\\\\\\\\\\", \\\\\\\\\\\\\\\"arguments\\\\\\\\\\\\\\\": {\\\\\\\\\\\\\\\"path\\\\\\\\\\\\\\\": \\\\\\\\\\\\\\\"src/main.rs\\\\\\\\\\\\\\\"}}]}\\\\\\\\n\\\\\\\\\\\\n        Do not use any other format. Respond with valid JSON only.\\\\\\\";\\\\n    let (content, _thinking, done_reason) = chat(QWEN35_4B, Some(system_prompt), \\\\n        \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    eprintln!(\\\\\\\"qwen3.5:4b json response: {:?}\\\\\\\", &content[..content.len().min(200)]);\\\\n    let calls = parse_tool_calls(&content, CapabilityProfile::Standard);\\\\n    assert!(!calls.is_empty(), \\\\\\\"should parse JSON tool calls\\\\\\\");\\\\n}\\\\n\\\\n// removed *_detect_tool_format test: detect_tool_format/ToolFormat removed from public API\\\\n// ─── qwen3:8b ────────────────────────────────────────────────────────────────\\\\n\\\\nconst QWEN3_8B: &str = \\\\\\\"qwen3:8b\\\\\\\";\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_qwen3_8b_plain_response() {\\\\n    if !ollama_available() || !model_available(QWEN3_8B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", QWEN3_8B);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(QWEN3_8B, None, \\\\\\\"What is 2+2? Just the number.\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty());\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_qwen3_8b_standard_format_emits_content() {\\\\n    if !ollama_available() || !model_available(QWEN3_8B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", QWEN3_8B);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(QWEN3_8B, Some(std_tool_system()), \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty(), \\\\\\\"qwen3:8b should emit content with <|tool> prompt\\\\\\\");\\\\n    let calls = parse_tool_calls(&content, CapabilityProfile::Standard);\\\\n    assert!(!calls.is_empty(), \\\\\\\"should parse tool call, content: {:?}\\\\\\\", content);\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_qwen3_8b_thinking_plus_content() {\\\\n    if !ollama_available() || !model_available(QWEN3_8B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", QWEN3_8B);\\\\n        return;\\\\n    }\\\\n    let (content, thinking, _) = chat(QWEN3_8B, Some(std_tool_system()), \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    // qwen3:8b should have both thinking AND content (unlike gemma heretic)\\\\n    assert!(!content.is_empty(), \\\\\\\"content should be non-empty\\\\\\\");\\\\n    // thinking may or may not be present depending on model config, but content must always be there\\\\n    let _ = thinking; // not asserting — model may suppress thinking in some configs\\\\n}\\\\n\\\\n// ─── phi4:14b-q4_K_M ─────────────────────────────────────────────────────────\\\\n\\\\nconst PHI4_14B: &str = \\\\\\\"phi4:14b-q4_K_M\\\\\\\";\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_phi4_plain_response() {\\\\n    if !ollama_available() || !model_available(PHI4_14B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", PHI4_14B);\\\\n        return;\\\\n    }\\\\n    let (content, thinking, done_reason) = chat(PHI4_14B, None, \\\\\\\"What is 2+2? Just the number.\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty());\\\\n    assert!(thinking.is_empty(), \\\\\\\"phi4 should have no thinking field\\\\\\\");\\\\n}\\\\n\\\\n#[test]\\\\n#[ignore]\\\\nfn test_phi4_standard_format() {\\\\n    if !ollama_available() || !model_available(PHI4_14B) {\\\\n        eprintln!(\\\\\\\"SKIP: {} not available\\\\\\\", PHI4_14B);\\\\n        return;\\\\n    }\\\\n    let (content, _thinking, done_reason) = chat(PHI4_14B, Some(std_tool_system()), \\\\\\\"Read the file src/main.rs\\\\\\\");\\\\n    assert_eq!(done_reason, \\\\\\\"stop\\\\\\\");\\\\n    assert!(!content.is_empty(), \\\\\\\"phi4 should produce content\\\\\\\");\\\\n}\\\\n\\\\n// removed *_detect_tool_format test: detect_tool_format/ToolFormat removed from public API\\\\n// ─── parse_tool_calls unit tests (not ignored — run in normal cargo test) ────\\\\n\\\\n// ─── sanitize + hallucination unit tests (not ignored) ──────────────────────\\\\n\\\\nuse yggdra::agent::{sanitize_model_output, is_hallucinated_output};\\\\n\\\\n#[test]\\\\nfn test_sanitize_heretic_training_artifacts() {\\\\n    // Real output from qwen3.5-heretic-4b:f16\\\\n    let input = \\\\\\\"\\\\\\\\n\\\\\\\\n4<|endoftext|><|im_start|>user\\\\\\\\nI'm a student who's learning English\\\\\\\";\\\\n    let cleaned = sanitize_model_output(input);\\\\n    assert_eq!(cleaned.trim(), \\\\\\\"4\\\\\\\");\\\\n    assert!(!cleaned.contains(\\\\\\\"<|endoftext|>\\\\\\\"));\\\\n    assert!(!cleaned.contains(\\\\\\\"<|im_start|>\\\\\\\"));\\\\n}\\\\n\\\\n#[test]\\\\nfn test_sanitize_heretic_thinking_artifacts() {\\\\n    // Real output from qwen3.5-heretic-9b:q4_K_M\\\\n    let input = \\\\\\\"\\\\\\\\n\\\\\\\\n<think>\\\\\\\\n\\\\\\\\n</think>\\\\\\\\n\\\\\\\\n4<|endoftext|><|im_start|>\\\\\\\\n<|im_start|>\\\\\\\\n\\\\\\\";\\\\n    let cleaned = sanitize_model_output(input);\\\\n    assert!(cleaned.contains(\\\\\\\"4\\\\\\\"));\\\\n    assert!(!cleaned.contains(\\\\\\\"<|im_start|>\\\\\\\"));\\\\n}\\\\n\\\\n// Removed test_hallucination_heretic_fake_conversation: relied on legacy [TOOL:]/[TOOL_OUTPUT:]\\\\n// bracket format being an indicator of hallucination. is_hallucinated_output now keys off\\\\n// JSON tool_calls + [TOOL_OUTPUT:] co-occurrence; the bracket-only legacy format has been\\\\n// retired from the parser entirely (see parse_tool_calls in src/agent.rs).\\\\n\\\\n// ─── qwen3.5:9b-q4_K_M (installed, working) ─────────────────────────────────\\\\n\\\\nconst QWEN35_9B: &str = \\\\\\\"qwen3.5:9b-q4_K_M\\\\\\\";\\\\n\